:root { color-scheme: dark; font-family: Inter, system-ui, sans-serif; }
body { margin: 0; min-height: 100vh; display: grid; place-items: center; background: #09090b; color: #f4f4f5; }
.shell { width: min(680px, calc(100vw - 32px)); }
.eyebrow { color: #22d3ee; text-transform: uppercase; letter-spacing: .12em; font-size: .75rem; }
h1 { font-size: clamp(2rem, 6vw, 4rem); margin: 0 0 1rem; }
button { border: 0; border-radius: 6px; padding: .75rem 1rem; background: #22d3ee; color: #082f49; font-weight: 700; }
